function t(n){try{if(!n)return null;const e=n.split(".");if(e.length!==3)return console.error("Invalid JWT format"),null;const o=e[1],a=atob(o),r=JSON.parse(a);return{email:r.email||r["cognito:username"],name:r.name||r.email?.split("@")[0]||"User",role:r.role||"user",sub:r.sub,exp:r.exp,iat:r.iat,iss:r.iss}}catch(e){return console.error("Failed to decode JWT:",e),null}}function i(n){const e=t(n);if(!e)return!0;const o=Math.floor(Date.now()/1e3);return e.exp<o+300}function l(n){const e=t(n);return e?{id:e.sub,email:e.email,name:e.name,role:e.role,createdAt:new Date(e.iat*1e3).toISOString()}:null}export{t as decodeJWT,l as getUserFromToken,i as isTokenExpired};
